#!/bin/bash
set -euo pipefail
cd "${Q2VMC_LAPNET_ROOT}" && python main.py --config=lapnet/configs/ferminet_system_configs.py --config.system.molecule_name=Li2 --config.network.name=psiformer --config.batch_size=4096 --config.optim.iterations=200000 --config.optim.optimizer=grpo --config.optim.forward_laplacian=true --config.log.stats_frequency=1 --config.log.save_frequency=10.0 --config.log.save_path=${Q2VMC_RESULTS_ROOT}/results/grpo__psiformer__Li2 --config.mcmc.burn_in=100 --config.mcmc.steps=30 --config.mcmc.move_width=0.02 --config.pretrain.iterations=5000 --config.pretrain.basis=ccpvdz --config.debug.deterministic=true --config.use_x64=false --config.optim.lr.rate=${Q2VMC_GRPO_LR_RATE:-0.001} --config.optim.grpo.inner_steps=${Q2VMC_GRPO_INNER_STEPS:-4} --config.optim.grpo.clip_epsilon=${Q2VMC_GRPO_CLIP_EPSILON:-0.2} --config.optim.grpo.max_advantage=${Q2VMC_GRPO_MAX_ADVANTAGE:-5.0} --config.optim.grpo.inner_optimizer=${Q2VMC_GRPO_INNER_OPTIMIZER:-adam} --config.optim.grpo.max_grad_norm=${Q2VMC_GRPO_MAX_GRAD_NORM:-1.0} > "${Q2VMC_RESULTS_ROOT}/results/grpo__psiformer__Li2/stdout.log" 2>&1
